import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

public class Solution {
    public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
        // Define the valid business lines in order
        String[] validBusinessLines = {"electronics", "grocery", "pharmacy", "restaurant"};

        // Filter valid coupons based on the conditions
        List<String> validCoupons = new ArrayList<>();
        for (int i = 0; i < code.length; i++) {
            if (!isActive[i]) {
                continue;
            }
            String codeStr = code[i];
            String businessStr = businessLine[i];

            // Check if code is non-empty and only contains allowed characters
            if (codeStr == null || codeStr.isEmpty() || !codeStr.matches("^[a-zA-Z0-9_]+$")) {
                continue;
            }

            // Check if business line is valid
            if (!Arrays.asList(validBusinessLines).contains(businessStr)) {
                continue;
            }

            validCoupons.add(codeStr);
        }

        // Sort the valid coupons first by business line order, then by code lexicographically
        validCoupons.sort((a, b) -> {
            int businessOrderA = Arrays.asList(validBusinessLines).indexOf(businessLine[0]);
            int businessOrderB = Arrays.asList(validBusinessLines).indexOf(businessLine[1]);
            if (businessOrderA != businessOrderB) {
                return Integer.compare(businessOrderA, businessOrderB);
            }
            return a.compareTo(b);
        });

        // Convert the list to an array
        return validCoupons.toArray(new String[0]);
    }
}
